//! Integration check (rubric Cat. 10): the committed sample graph fixture is
//! exactly what the generator produces for its pinned config, and it loads back
//! into the logical model cleanly.
//!
//! The fixture `tests/fixtures/sample_graph.jsonl` is a tiny (≈6 KB),
//! license-clean, **generated** graph — no third-party data (see
//! `docs/process/open-source-guardrails.md`). It is regenerated by:
//!
//! ```bash
//! cargo run -- generate-dataset --nodes 12 --edges 20 --seed 0 \
//!     --out tests/fixtures/sample_graph.jsonl
//! ```
//!
//! This test pins that command's output: if the generator's algorithm changes,
//! this fails and the committed fixture must be deliberately refreshed (so the
//! sample never silently drifts from the generator, and reproducibility is
//! provable from the repo alone).

use std::io::{BufReader, Cursor};
use std::path::PathBuf;

use caerostris_db::dataset::{GenConfig, Generator, GraphRecord, read_records, write_jsonl};
use caerostris_db::model::{Edge, Node, PropertyValue};

/// The pinned config the committed sample was generated with.
const SAMPLE_NODES: u64 = 12;
const SAMPLE_EDGES: u64 = 20;
const SAMPLE_SEED: u64 = 0;

fn fixture_path() -> PathBuf {
    PathBuf::from(env!("CARGO_MANIFEST_DIR")).join("tests/fixtures/sample_graph.jsonl")
}

fn pinned_generator() -> Generator {
    Generator::new(GenConfig::small(SAMPLE_NODES, SAMPLE_EDGES, SAMPLE_SEED))
}

#[test]
fn committed_sample_matches_the_generator_byte_for_byte() {
    let committed = std::fs::read(fixture_path()).unwrap_or_else(|e| {
        panic!(
            "missing committed sample {}: {e} — regenerate with the command in this file's docs",
            fixture_path().display()
        )
    });

    let mut regenerated: Vec<u8> = Vec::new();
    write_jsonl(&pinned_generator(), &mut regenerated).expect("regenerate sample");

    assert_eq!(
        committed, regenerated,
        "committed sample has drifted from the generator — if the generator change is \
         intentional, refresh tests/fixtures/sample_graph.jsonl (see this file's docs)"
    );
}

#[test]
fn committed_sample_loads_into_the_model() {
    let file = std::fs::File::open(fixture_path()).expect("open sample");
    let mut nodes: Vec<Node> = Vec::new();
    let mut edges: Vec<Edge> = Vec::new();
    let mut meta_counts: Option<(u64, u64)> = None;

    for rec in read_records(BufReader::new(file)) {
        match rec.expect("parse line") {
            GraphRecord::Meta {
                node_count,
                edge_count,
                ..
            } => meta_counts = Some((node_count, edge_count)),
            GraphRecord::Node { node } => nodes.push(node),
            GraphRecord::Edge { edge } => edges.push(edge),
        }
    }

    assert_eq!(meta_counts, Some((SAMPLE_NODES, SAMPLE_EDGES)));
    assert_eq!(nodes.len() as u64, SAMPLE_NODES);
    assert_eq!(edges.len() as u64, SAMPLE_EDGES);

    // Every node carries the documented text properties and a label.
    for node in &nodes {
        assert!(!node.labels.is_empty());
        assert!(matches!(
            node.property("name"),
            Some(PropertyValue::String(_))
        ));
        assert!(matches!(
            node.property("country"),
            Some(PropertyValue::String(_))
        ));
    }
    // Every edge is directed within the node-id range and typed.
    for edge in &edges {
        assert!(edge.source.get() < SAMPLE_NODES);
        assert!(edge.target.get() < SAMPLE_NODES);
        assert!(!edge.rel_type.is_empty());
    }
}

#[test]
fn sample_read_back_equals_generated_graph() {
    // Round-trip the committed bytes back through the reader and confirm the
    // records equal a fresh in-memory generation — the strongest statement of
    // "the portable form preserves the logical graph".
    let g = pinned_generator();
    let expected_nodes: Vec<Node> = g.nodes().collect();
    let expected_edges: Vec<Edge> = g.edges().collect();

    let bytes = std::fs::read(fixture_path()).expect("read sample");
    let mut nodes = Vec::new();
    let mut edges = Vec::new();
    for rec in read_records(Cursor::new(bytes)) {
        match rec.expect("parse") {
            GraphRecord::Meta { .. } => {}
            GraphRecord::Node { node } => nodes.push(node),
            GraphRecord::Edge { edge } => edges.push(edge),
        }
    }
    assert_eq!(nodes, expected_nodes);
    assert_eq!(edges, expected_edges);
}
